  1→"use client";
  2→
  3→import {
  4→  BarChart,
  5→  Brain,
  6→  Clock,
  7→  History,
  8→  LayoutGrid,
  9→  MessageCircle,
 10→  Moon,
 11→  Sun,
 12→  Users,
 13→} from "lucide-react";
 14→import Link from "next/link";
 15→import { usePathname } from "next/navigation";
 16→import { useTheme } from "next-themes";
 17→import { Logo } from "@/components/logo";
 18→import { OrgSwitcher } from "@/components/org-switcher";
 19→import { PricingModal } from "@/components/pricing-modal";
 20→import { Button } from "@/components/ui/button";
 21→import { useSubscriptionContext } from "@/context/subscription-context";
 22→import { cn } from "@/lib/utils";
 23→
 24→const NAV_ITEMS = [
 25→  {
 26→    label: "Sandboxes",
 27→    href: "/dashboard",
 28→    icon: LayoutGrid,
 29→    match: (p: string) => p === "/dashboard" || p.startsWith("/sandboxes"),
 30→  },
 31→  {
 32→    label: "Members",
 33→    href: "/members",
 34→    icon: Users,
 35→    match: (p: string) => p === "/members",
 36→  },
 37→];
 38→
 39→const SANDBOX_NAV_ITEMS = [
 40→  {
 41→    label: "Channels",
 42→    icon: MessageCircle,
 43→    segment: "channels",
 44→  },
 45→  {
 46→    label: "Crons",
 47→    icon: Clock,
 48→    segment: "cron",
 49→  },
 50→  {
 51→    label: "Models",
 52→    icon: Brain,
 53→    segment: "models",
 54→  },
 55→  {
 56→    label: "Sessions",
 57→    icon: History,
 58→    segment: "sessions",
 59→  },
 60→  {
 61→    label: "Usage",
 62→    icon: BarChart,
 63→    segment: "usage",
 64→  },
 65→];
 66→
 67→interface SidebarUser {
 68→  name: string;
 69→  email: string;
 70→  image?: string | null;
 71→}
 72→
 73→interface AppSidebarProps {
 74→  user: SidebarUser;
 75→}
 76→
 77→const CREDITS_USED = 1_250;
 78→const CREDITS_TOTAL = 5_000;
 79→
 80→export function AppSidebar({ user }: AppSidebarProps) {
 81→  const pathname = usePathname();
 82→  const { resolvedTheme, setTheme } = useTheme();
 83→
 84→  const sandboxMatch = pathname.match(/^\/sandboxes\/([^/]+)/);
 85→  const activeSandboxId = sandboxMatch?.[1] ?? null;
 86→
 87→  const { data: subscription, isLoading } = useSubscriptionContext();
 88→  const isSubscribed = subscription?.status === "subscribed";
 89→
 90→  function toggleTheme() {
 91→    setTheme(resolvedTheme === "dark" ? "light" : "dark");
 92→  }
 93→
 94→  return (
 95→    <aside className="flex h-screen w-56 flex-col border-r border-sidebar-border bg-sidebar text-sidebar-foreground">
 96→      {/* Logo */}
 97→      <div className="flex h-14 items-center justify-between border-b border-sidebar-border px-4">
 98→        <Logo size="sm" href="/dashboard" />
 99→        <Button
100→          variant="ghost"
101→          size="icon"
102→          className="size-7 shrink-0 text-muted-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
103→          onClick={toggleTheme}
104→          aria-label="Toggle theme"
105→        >
106→          {resolvedTheme === "dark" ? (
107→            <Sun className="size-3.5" />
108→          ) : (
109→            <Moon className="size-3.5" />
110→          )}
111→        </Button>
112→      </div>
113→
114→      {/* Nav */}
115→      <nav className="flex flex-1 flex-col gap-0.5 overflow-y-auto p-3">
116→        {NAV_ITEMS.map(({ label, href, icon: Icon, match }) => {
117→          const isActive = match(pathname);
118→          return (
119→            <Link
120→              key={href}
121→              href={href}
122→              className={cn(
123→                "flex items-center gap-2.5 rounded-md px-2.5 py-2 text-sm transition-colors",
124→                isActive
125→                  ? "bg-sidebar-accent font-medium text-sidebar-accent-foreground"
126→                  : "text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
127→              )}
128→            >
129→              <Icon className="size-4 shrink-0" />
130→              {label}
131→            </Link>
132→          );
133→        })}
134→
135→        {activeSandboxId && (
136→          <>
137→            <div className="mt-3 mb-1 px-2.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
138→              Sandbox
139→            </div>
140→            {SANDBOX_NAV_ITEMS.map(({ label, icon: Icon, segment }) => {
141→              const href = `/sandboxes/${activeSandboxId}/${segment}`;
142→              const isActive = pathname === href;
143→              return (
144→                <Link
145→                  key={segment}
146→                  href={href}
147→                  className={cn(
148→                    "flex items-center gap-2.5 rounded-md px-2.5 py-2 text-sm transition-colors",
149→                    isActive
150→                      ? "bg-sidebar-accent font-medium text-sidebar-accent-foreground"
151→                      : "text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground",
152→                  )}
153→                >
154→                  <Icon className="size-4 shrink-0" />
155→                  {label}
156→                </Link>
157→              );
158→            })}
159→          </>
160→        )}
161→      </nav>
162→      {!(isLoading || isSubscribed) && (
163→        <div className="border-t border-sidebar-border px-3 py-3">
164→          <PricingModal>
165→            <Button variant="outline" className="w-full">
166→              Upgrade
167→            </Button>
168→          </PricingModal>
169→        </div>
170→      )}
171→
172→      {/* Credits */}
173→      <div className="border-t border-sidebar-border px-3 py-3">
174→        <div className="rounded-lg bg-sidebar-accent/50 px-3 py-2.5">
175→          <div className="flex items-center justify-between text-[11px]">
176→            <span className="font-medium text-sidebar-foreground">Credits</span>
177→            <span className="text-muted-foreground">
178→              {CREDITS_USED.toLocaleString()} / {CREDITS_TOTAL.toLocaleString()}
179→            </span>
180→          </div>
181→          <div className="mt-2 h-1.5 w-full overflow-hidden rounded-full bg-sidebar-border">
182→            <div
183→              className="h-full rounded-full bg-primary transition-all"
184→              style={{ width: `${(CREDITS_USED / CREDITS_TOTAL) * 100}%` }}
185→            />
186→          </div>
187→          <p className="mt-1.5 text-[10px] text-muted-foreground">
188→            {(CREDITS_TOTAL - CREDITS_USED).toLocaleString()} remaining
189→          </p>
190→        </div>
191→      </div>
192→
193→      {/* Org + User dropdown */}
194→      <div className="border-t border-sidebar-border p-3">
195→        <OrgSwitcher user={user} />
196→      </div>
197→    </aside>
198→  );
199→}
