 1→import { redirect } from "next/navigation";
 2→import { getAuthedSession } from "@/server/action-utils";
 3→import { ImpersonationBanner } from "@/components/impersonation-banner";
 4→import { AppSidebar } from "@/components/sidebar";
 5→import { SubscriptionProvider } from "@/context/subscription-context";
 6→
 7→export default async function AppLayout({
 8→  children,
 9→}: {
10→  children: React.ReactNode;
11→}) {
12→  const session = await getAuthedSession().catch(() => null);
13→  if (!session) redirect("/sign-in");
14→
15→  const { user } = session;
16→  const isImpersonating = !!(
17→    session.session as { impersonatedBy?: string | null }
18→  ).impersonatedBy;
19→
20→  if (!user.emailVerified) redirect("/email-verification");
21→
22→  return (
23→    <SubscriptionProvider>
24→      <div className="flex h-screen flex-col overflow-hidden bg-background">
25→        {isImpersonating && (
26→          <ImpersonationBanner userName={user.name} userEmail={user.email} />
27→        )}
28→        <div className="flex flex-1 overflow-hidden">
29→          <AppSidebar user={user} />
30→          <main className="flex flex-1 flex-col overflow-y-auto">
31→            {children}
32→          </main>
33→        </div>
34→      </div>
35→    </SubscriptionProvider>
36→  );
37→}
