  1→"use client";
  2→
  3→import Image from "next/image";
  4→import type {
  5→  ChannelsViewProps,
  6→  DiscordStatus,
  7→  SlackStatus,
  8→  TelegramStatus,
  9→} from "@/app/(app)/sandboxes/[id]/channels/_components/types";
 10→import { Button } from "@/components/ui/button";
 11→
 12→const TELEGRAM_ICON_SRC = "/Icons/telegram.svg";
 13→const SLACK_ICON_SRC = "/Icons/slack.svg";
 14→const DISCORD_ICON_SRC = "/Icons/discord.svg";
 15→
 16→import { useChannelsStatus } from "@/app/(app)/sandboxes/[id]/channels/_hooks/use-channels-status";
 17→
 18→function isChannelConnected(options: {
 19→  key: string;
 20→  telegram?: TelegramStatus;
 21→  discord?: DiscordStatus;
 22→  slack?: SlackStatus;
 23→}): boolean {
 24→  const { key, telegram, discord, slack } = options;
 25→
 26→  if (key === "telegram" && telegram) {
 27→    return telegram.configured && telegram.running;
 28→  }
 29→
 30→  if (key === "discord" && discord) {
 31→    return discord.configured && discord.running;
 32→  }
 33→
 34→  if (key === "slack" && slack) {
 35→    return slack.configured && slack.running;
 36→  }
 37→
 38→  return false;
 39→}
 40→
 41→export function ChannelsView({ sandboxId }: ChannelsViewProps) {
 42→  const {
 43→    snapshot,
 44→    loading,
 45→    lastError: _lastError,
 46→    lastSuccessAt: _lastSuccessAt,
 47→    refetch,
 48→  } = useChannelsStatus(sandboxId);
 49→
 50→  const channels = snapshot?.channels as Record<string, unknown> | null;
 51→  const telegram = (channels?.telegram ?? undefined) as
 52→    | TelegramStatus
 53→    | undefined;
 54→  const discord = (channels?.discord ?? undefined) as DiscordStatus | undefined;
 55→  const slack = (channels?.slack ?? undefined) as SlackStatus | undefined;
 56→
 57→  const entries = [
 58→    {
 59→      key: "telegram",
 60→      name: "Telegram",
 61→      description:
 62→        "Connect your Telegram bot to send and receive messages from your assistant.",
 63→      isavailable: true,
 64→    },
 65→    {
 66→      key: "slack",
 67→      name: "Slack",
 68→      description: "Bring your assistant into Slack channels and DMs.",
 69→      isavailable: false,
 70→    },
 71→    {
 72→      key: "discord",
 73→      name: "Discord",
 74→      description:
 75→        "Use your assistant inside Discord servers and direct messages.",
 76→      isavailable: false,
 77→    },
 78→  ] as const;
 79→
 80→  if (loading && !snapshot) {
 81→    return (
 82→      <section className="flex flex-col gap-6 p-6 md:p-8">
 83→        <div className="flex justify-start items-center">
 84→          <div>
 85→            <h1 className="text-xl font-semibold tracking-tight">Channels</h1>
 86→            <p className="mt-0.5 text-sm text-muted-foreground">
 87→              Connect your assistant to channels and receive messages from your
 88→              users.
 89→            </p>
 90→          </div>
 91→        </div>
 92→        <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
 93→          <div className="col-span-full flex items-center justify-center py-16">
 94→            <div className="flex items-center gap-3 text-muted-foreground">
 95→              <span
 96→                className="h-4 w-4 rounded-full border-2 border-muted-foreground border-t-transparent animate-spin"
 97→                aria-hidden="true"
 98→              />
 99→              <span className="text-sm">Loading channels…</span>
100→            </div>
101→          </div>
102→        </section>
103→      </section>
104→    );
105→  }
106→
107→  return (
108→    <section className="flex flex-col gap-6 p-6 md:p-8">
109→      <div className="flex justify-between items-center">
110→        <div>
111→          <h1 className="text-xl font-semibold tracking-tight">Channels</h1>
112→          <p className="mt-0.5 text-sm text-muted-foreground">
113→            Connect your assistant to channels and receive messages from your
114→            users.
115→          </p>
116→        </div>
117→
118→        <Button type="button" onClick={() => refetch()}>
119→          Refresh
120→        </Button>
121→      </div>
122→      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 ">
123→        {entries.map((entry) => {
124→          let iconConfig = { src: DISCORD_ICON_SRC, alt: "Discord" };
125→          if (entry.key === "telegram") {
126→            iconConfig = { src: TELEGRAM_ICON_SRC, alt: "Telegram" };
127→          } else if (entry.key === "slack") {
128→            iconConfig = { src: SLACK_ICON_SRC, alt: "Slack" };
129→          }
130→
131→          const isConnected = isChannelConnected({
132→            key: entry.key,
133→            telegram,
134→            discord,
135→            slack,
136→          });
137→
138→          const buttonLabel = isConnected ? "Connected" : "Not Connected";
139→
140→          return (
141→            <article
142→              key={entry.key}
143→              className="flex flex-col justify-between rounded-xl border bg-card p-5 shadow-sm"
144→            >
145→              <div className="flex items-start gap-3">
146→                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-muted text-muted-foreground">
147→                  <Image
148→                    src={iconConfig.src}
149→                    alt={iconConfig.alt}
150→                    width={24}
151→                    height={24}
152→                    className="h-5 w-5"
153→                  />
154→                </div>
155→                <div className="space-y-1">
156→                  <h3 className="text-sm font-medium">{entry.name}</h3>
157→                  <p className="text-xs text-muted-foreground">
158→                    {entry.description}
159→                  </p>
160→                </div>
161→              </div>
162→              <span
163→                className={`mt-4 inline-flex w-fit items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium ${
164→                  isConnected
165→                    ? "bg-green-500/10 text-green-600"
166→                    : entry.isavailable
167→                      ? "bg-destructive/10 text-destructive"
168→                      : "bg-muted text-muted-foreground"
169→                }`}
170→              >
171→                {isConnected && (
172→                  <span className="h-1.5 w-1.5 rounded-full bg-green-500" />
173→                )}
174→                {!entry.isavailable
175→                  ? "Coming soon"
176→                  : isConnected
177→                    ? "Connected"
178→                    : "Not Connected"}
179→              </span>
180→            </article>
181→          );
182→        })}
183→      </div>
184→    </section>
185→  );
186→}
