  1→"use client";
  2→
  3→import {
  4→  Bot,
  5→  Calendar,
  6→  Loader2,
  7→  RefreshCw,
  8→  Send,
  9→  Trash2,
 10→  Zap,
 11→} from "lucide-react";
 12→import Image from "next/image";
 13→import { useState } from "react";
 14→import { toast } from "sonner";
 15→import { PaywallBanner } from "@/components/paywall-banner";
 16→import { PricingModal } from "@/components/pricing-modal";
 17→import {
 18→  AlertDialog,
 19→  AlertDialogAction,
 20→  AlertDialogCancel,
 21→  AlertDialogContent,
 22→  AlertDialogDescription,
 23→  AlertDialogFooter,
 24→  AlertDialogHeader,
 25→  AlertDialogTitle,
 26→  AlertDialogTrigger,
 27→} from "@/components/ui/alert-dialog";
 28→import { Badge } from "@/components/ui/badge";
 29→import { Button } from "@/components/ui/button";
 30→import {
 31→  Card,
 32→  CardContent,
 33→  CardDescription,
 34→  CardHeader,
 35→  CardTitle,
 36→} from "@/components/ui/card";
 37→import { Input } from "@/components/ui/input";
 38→import { useSubscriptionContext } from "@/context/subscription-context";
 39→import {
 40→  RUNTIME_STATUS_BADGE_VARIANT,
 41→  RUNTIME_STATUS_DOT,
 42→  RUNTIME_STATUS_LABEL,
 43→  type SandboxRuntimeStatus,
 44→} from "@/lib/sandbox";
 45→import type { Sandbox } from "@/server/db/schema";
 46→import {
 47→  useApproveTelegramPairing,
 48→  useDeleteSandbox,
 49→  useRestartGateway,
 50→  useSandboxRuntime,
 51→  useWakeSandbox,
 52→} from "../_hooks/use-sandbox";
 53→
 54→interface SandboxDetailProps {
 55→  sandbox: Sandbox;
 56→}
 57→
 58→export function SandboxDetail({ sandbox }: SandboxDetailProps) {
 59→  const [pairingCode, setPairingCode] = useState("");
 60→  const [restarting, setRestarting] = useState(false);
 61→  const [pricingOpen, setPricingOpen] = useState(false);
 62→  const { data: subscription, isLoading: subscriptionLoading } =
 63→    useSubscriptionContext();
 64→  const canAct =
 65→    !subscriptionLoading &&
 66→    (subscription?.status === "subscribed" || subscription?.status === "trial");
 67→  const {
 68→    data: runtime,
 69→    isLoading: runtimeLoading,
 70→    isFetching: runtimeFetching,
 71→    isError: runtimeError,
 72→    error: runtimeErrorObj,
 73→    refetch: refetchRuntime,
 74→  } = useSandboxRuntime(sandbox.id);
 75→  const { mutate: wake, isPending: waking } = useWakeSandbox();
 76→  const { mutate: approvePairing, isPending: approving } =
 77→    useApproveTelegramPairing();
 78→  const { mutate: deleteSandbox, isPending: deleting } = useDeleteSandbox();
 79→  const { mutate: restartGateway } = useRestartGateway();
 80→
 81→  function getRuntimeStatus(): SandboxRuntimeStatus {
 82→    if (runtimeError) return "error";
 83→    if (runtimeLoading) return "unknown";
 84→    return (runtime?.state as SandboxRuntimeStatus) ?? "unknown";
 85→  }
 86→
 87→  const runtimeStatus = getRuntimeStatus();
 88→  const isRunning = runtimeStatus === "running";
 89→  const statusRefreshing = runtimeLoading || runtimeFetching;
 90→
 91→  let errorMessage = null;
 92→  if (runtimeError) {
 93→    errorMessage =
 94→      runtimeErrorObj instanceof Error
 95→        ? runtimeErrorObj.message
 96→        : "Failed to fetch runtime status";
 97→  }
 98→
 99→  function isSubscriptionRequiredError(err: unknown) {
100→    return (err as { code?: string }).code === "SUBSCRIPTION_REQUIRED";
101→  }
102→
103→  function handleWake() {
104→    wake(
105→      { sandboxId: sandbox.id },
106→      {
107→        onSuccess: () => toast.success("Sandbox is awake"),
108→        onError: (err) => {
109→          if (isSubscriptionRequiredError(err)) {
110→            setPricingOpen(true);
111→            return;
112→          }
113→          toast.error(
114→            err instanceof Error ? err.message : "Failed to wake bot",
115→          );
116→        },
117→      },
118→    );
119→  }
120→
121→  const handleApprovePairing = (e?: React.FormEvent) => {
122→    e?.preventDefault();
123→    const code = pairingCode.trim().toUpperCase();
124→    if (!code) return;
125→
126→    approvePairing(
127→      { sandboxId: sandbox.id, pairingCode: code },
128→      {
129→        onSuccess: () => {
130→          toast.success("Pairing code approved");
131→          setPairingCode("");
132→        },
133→        onError: (err) => {
134→          if (isSubscriptionRequiredError(err)) {
135→            setPricingOpen(true);
136→            return;
137→          }
138→          toast.error(
139→            err instanceof Error
140→              ? err.message
141→              : "Failed to approve pairing code",
142→          );
143→        },
144→      },
145→    );
146→  };
147→
148→  const handleRestartGateway = () => {
149→    setRestarting(true);
150→
151→    restartGateway(
152→      { sandboxId: sandbox.id },
153→      {
154→        onSuccess: () => {
155→          toast.success("Gateway restarted");
156→          setRestarting(false);
157→        },
158→        onError: (err) => {
159→          if (isSubscriptionRequiredError(err)) {
160→            setRestarting(false);
161→            setPricingOpen(true);
162→            return;
163→          }
164→          toast.error(
165→            err instanceof Error ? err.message : "Failed to restart gateway",
166→          );
167→          setRestarting(false);
168→        },
169→      },
170→    );
171→  };
172→
173→  return (
174→    <div className="space-y-8">
175→      <PaywallBanner
176→        subscription={subscription}
177→        onUpgrade={() => setPricingOpen(true)}
178→      />
179→
180→      {/* Header Section */}
181→      <div className="flex flex-wrap items-end justify-between gap-6 border-b border-border/50 pb-8">
182→        <div className="flex items-center gap-6">
183→          <div className="flex size-16 items-center justify-center rounded-2xl bg-primary/10 shadow-inner ring-1 ring-primary/20">
184→            <Bot className="size-10 text-primary" />
185→          </div>
186→          <div className="space-y-1.5">
187→            <h1 className="text-4xl font-bold tracking-tight text-foreground">
188→              {sandbox.name}
189→            </h1>
190→            <div className="flex items-center gap-3">
191→              <Badge
192→                variant={RUNTIME_STATUS_BADGE_VARIANT[runtimeStatus]}
193→                className="px-3 py-1 text-xs font-semibold uppercase tracking-wider"
194→              >
195→                <span
