 1→"use client";
 2→
 3→import { useQuery, useQueryClient } from "@tanstack/react-query";
 4→import type { ChannelsStatusSnapshot } from "@/app/(app)/sandboxes/[id]/channels/_components/types";
 5→import { getChannelsStatus } from "@/server/actions/channels.action";
 6→
 7→export function channelsStatusKey(sandboxId: string) {
 8→  return ["channels-status", sandboxId] as const;
 9→}
10→
11→export function useChannelsStatus(sandboxId: string) {
12→  const queryClient = useQueryClient();
13→
14→  const query = useQuery({
15→    queryKey: channelsStatusKey(sandboxId),
16→    queryFn: async () => {
17→      if (!sandboxId) throw new Error("No sandbox");
18→      const result = await getChannelsStatus({ sandboxId });
19→      if (result && typeof result === "object" && "error" in result) {
20→        throw Object.assign(new Error(String(result.error)), { code: result.error });
21→      }
22→      return result;
23→    },
24→    enabled: !!sandboxId,
25→  });
26→
27→  function refetch() {
28→    if (sandboxId) {
29→      void queryClient.invalidateQueries({
30→        queryKey: channelsStatusKey(sandboxId),
31→      });
32→    }
33→  }
34→
35→  return {
36→    snapshot: query.data as ChannelsStatusSnapshot | undefined,
37→    loading: query.isLoading,
38→    isFetching: query.isFetching,
39→    lastError: query.error instanceof Error ? query.error.message : null,
40→    lastSuccessAt: query.dataUpdatedAt ?? null,
41→    refetch,
42→  };
43→}
