 3→import { useCallback } from "react";
 4→import { toast } from "sonner";
 5→import { useSandboxes } from "@/app/(app)/dashboard/_hooks/use-sandboxes";
 6→import { SessionsView } from "@/app/(app)/sandboxes/[id]/sessions/_components/sessions-view";
 7→import type { SessionsProps } from "@/app/(app)/sandboxes/[id]/sessions/_components/types";
 8→import { useSessionsList } from "@/app/(app)/sandboxes/[id]/sessions/_hooks/use-sessions-list";
 9→import { deleteSession, patchSession } from "@/server/actions/session.action";
10→
11→export default function SessionsPage() {
12→  const searchParams = useSearchParams();
13→  const sandboxIdFromUrl = searchParams.get("sandboxId");
14→  const { data: sandboxes } = useSandboxes();
15→  const sandboxId =
16→    sandboxIdFromUrl ?? (sandboxes?.[0] ? sandboxes[0].id : null);
17→
18→  const { result, loading, error, refetch } = useSessionsList(sandboxId);
19→
20→  const handlePatch = useCallback(
21→    async (key: string, patch: Parameters<SessionsProps["onPatch"]>[1]) => {
22→      if (!sandboxId) {
23→        toast.error("No sandbox selected");
24→        return;
25→      }
26→      try {
27→        await patchSession({ sandboxId, key, patch });
28→        toast.success("Session updated");
29→        refetch();
30→      } catch (err) {
31→        toast.error(
32→          err instanceof Error ? err.message : "Failed to patch session",
33→        );
34→      }
35→    },
36→    [sandboxId, refetch],
37→  );
38→
39→  const handleDelete = useCallback(
40→    async (key: string) => {
41→      if (!confirm(`Delete session "${key}"?`)) return;
42→      if (!sandboxId) {
43→        toast.error("No sandbox selected");
44→        return;
45→      }
46→      try {
47→        await deleteSession({ sandboxId, key });
48→        toast.success("Session deleted");
49→        refetch();
50→      } catch (err) {
51→        toast.error(
52→          err instanceof Error ? err.message : "Failed to delete session",
53→        );
54→      }
55→    },
56→    [sandboxId, refetch],
57→  );
58→
59→  const props: SessionsProps = {
60→    loading,
61→    result: result ?? null,
62→    error,
63→    basePath: "",
64→    onRefresh: refetch,
65→    onPatch: handlePatch,
66→    onDelete: handleDelete,
67→  };
68→
69→  return <SessionsView {...props} />;
70→}
