 12→  useModelsStatus,
 13→  useProviderModels,
 14→} from "../_hooks/use-models";
 15→
 16→// ── Provider config ──────────────────────────────────────────────────────────
 17→
 18→type ProviderId = "openai" | "anthropic" | "openrouter";
 19→
 20→interface ProviderOption {
 21→  id: ProviderId;
 22→  name: string;
 23→  placeholder: string;
 24→}
 25→
 26→const PROVIDERS: ProviderOption[] = [
 27→  { id: "openai", name: "OpenAI", placeholder: "sk-..." },
 28→  { id: "anthropic", name: "Anthropic", placeholder: "sk-ant-..." },
 29→  { id: "openrouter", name: "OpenRouter", placeholder: "sk-or-..." },
 30→];
 31→
 32→interface ConfiguredModel {
 33→  key: string;
 34→  name: string;
 35→  isDefault: boolean;
 36→  provider: "openai" | "anthropic" | "openrouter" | "other";
 37→}
 38→
 39→// ── Component ────────────────────────────────────────────────────────────────
 40→
 41→interface ModelsViewProps {
 42→  sandboxId: string;
 43→}
 44→
 45→export function ModelsView({ sandboxId }: ModelsViewProps) {
 46→  const { data: status, isLoading: statusLoading } = useModelsStatus(sandboxId);
 47→  const { data: configuredModels, isLoading: configuredLoading } =
 48→    useConfiguredModels(sandboxId);
 49→  const { configure, setDefault, busy } = useModelsMutations(sandboxId);
 50→
 51→  const [selectedProvider, setSelectedProvider] = useState<ProviderId | null>(
 52→    null,
 53→  );
 54→  const [apiKey, setApiKey] = useState("");
 55→  const [showKey, setShowKey] = useState(false);
 56→  const [selectedModels, setSelectedModels] = useState<Set<string>>(new Set());
 57→  const [defaultModel, setDefaultModel] = useState<string | null>(null);
 58→
 59→  const provider = PROVIDERS.find((p) => p.id === selectedProvider);
 60→
 61→  // Fetch models dynamically when a provider is selected
 62→  const { data: providerModels, isLoading: modelsLoading } = useProviderModels(
 63→    sandboxId,
 64→    selectedProvider,
 65→  );
 66→
 67→  // Pre-select configured models when provider models load
 68→  useEffect(() => {
 69→    if (!(providerModels && configuredModels && selectedProvider)) return;
 70→    const providerKeys = new Set(providerModels.map((m) => m.id));
 71→    const alreadyConfigured = (configuredModels as ConfiguredModel[]).filter(
 72→      (m) => providerKeys.has(m.key),
 73→    );
 74→    if (alreadyConfigured.length > 0) {
 75→      setSelectedModels(new Set(alreadyConfigured.map((m) => m.key)));
 76→      const def = alreadyConfigured.find((m) => m.isDefault);
 77→      setDefaultModel(def?.key ?? alreadyConfigured[0].key);
 78→    }
 79→  }, [providerModels, configuredModels, selectedProvider]);
 80→
 81→  function handleProviderSelect(id: ProviderId) {
 82→    setSelectedProvider(id);
 83→    setApiKey("");
 84→    setShowKey(false);
 85→    setSelectedModels(new Set());
 86→    setDefaultModel(null);
 87→  }
 88→
 89→  function toggleModel(id: string) {
 90→    setSelectedModels((prev) => {
 91→      const next = new Set(prev);
 92→      if (next.has(id)) {
 93→        next.delete(id);
 94→        if (defaultModel === id) setDefaultModel(null);
 95→      } else {
 96→        next.add(id);
 97→        if (next.size === 1) setDefaultModel(id);
 98→      }
 99→      return next;
100→    });
101→  }
102→
103→  // Check if selected provider is already authenticated
104→  const providerConfigured = configuredModels
105→    ? (configuredModels as ConfiguredModel[]).some(
106→        (m) => m.provider === selectedProvider,
107→      )
108→    : false;
109→
110→  function handleConfigure() {
111→    if (!(selectedProvider && selectedModels.size > 0 && defaultModel)) return;
112→    if (!(providerConfigured || apiKey.trim())) return;
113→    configure.mutate(
114→      {
115→        provider: selectedProvider,
116→        apiKey: apiKey.trim(),
117→        models: Array.from(selectedModels),
118→        defaultModel,
119→      },
120→      {
121→        onSuccess: () => {
122→          toast.success(
123→            `${selectedModels.size} model${
124→              selectedModels.size > 1 ? "s" : ""
125→            } configured. Default: ${defaultModel}.`,
126→          );
127→        },
128→      },
129→    );
130→  }
131→
132→  const canConfigure =
133→    !!selectedProvider &&
134→    (providerConfigured || !!apiKey.trim()) &&
135→    selectedModels.size > 0 &&
136→    !!defaultModel &&
137→    !busy;
138→
139→  return (
140→    <section className="flex flex-col gap-6 p-6 md:p-8">
141→      <div className="flex justify-between items-center">
142→        <div>
143→          <h1 className="text-xl font-semibold tracking-tight">Models</h1>
144→          <p className="mt-0.5 text-sm text-muted-foreground">
145→            Set up a provider API key and default model for this sandbox.
146→          </p>
147→        </div>
148→      </div>
149→      <div className="w-full grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
150→        <div className="flex flex-col lg:col-span-2 gap-3 rounded-lg border p-4 bg-card ">
151→          {/* Step 1: Choose provider */}
152→          <div className="space-y-3">
153→            <div>
154→              <h3 className="font-semibold text-sm">1. Choose Provider</h3>
155→              <p className="text-xs text-muted-foreground">
156→                Select an LLM provider.
157→              </p>
158→            </div>
159→            <div className="grid grid-cols-3 gap-3">
160→              {PROVIDERS.map((p) => (
161→                <button
162→                  key={p.id}
163→                  type="button"
164→                  disabled={busy}
165→                  onClick={() => handleProviderSelect(p.id)}
166→                  className={cn(
167→                    "rounded-lg border p-3 text-center text-sm font-medium transition-colors",
168→                    selectedProvider === p.id
169→                      ? "border-primary bg-primary/5 text-primary"
170→                      : "hover:bg-accent/50",
171→                  )}
172→                >
173→                  {p.name}
174→                </button>
175→              ))}
176→            </div>
177→          </div>
178→
179→          {/* Step 2: API key */}
180→          {provider && (
181→            <div className="space-y-3">
182→              <div>
183→                <h3 className="font-semibold text-sm">2. API Key</h3>
184→                <p className="text-xs text-muted-foreground">
185→                  Enter your {provider.name} API key. It will be stored in the
186→                  sandbox config.
187→                </p>
188→              </div>
189→              <div className="relative">
190→                <Key className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
191→                <Input
192→                  type={showKey ? "text" : "password"}
193→                  placeholder={provider.placeholder}
194→                  value={apiKey}
195→                  onChange={(e) => setApiKey(e.target.value)}
196→                  disabled={busy}
197→                  className="pl-9 pr-9"
198→                  autoComplete="off"
199→                />
200→                <button
201→                  type="button"
202→                  onClick={() => setShowKey((v) => !v)}
203→                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
204→                >
205→                  {showKey ? (
206→                    <EyeOff className="size-4" />
207→                  ) : (
208→                    <Eye className="size-4" />
209→                  )}
210→                </button>
211→              </div>
212→            </div>
213→          )}
214→
215→          {/* Step 3: Choose models */}
216→          {provider && (providerConfigured || apiKey.trim()) && (
217→            <div className="space-y-3">
218→              <div>
219→                <h3 className="font-semibold text-sm">3. Choose Models</h3>
220→                <p className="text-xs text-muted-foreground">
221→                  Select one or more models to allowlist, then pick a default.
222→                </p>
223→              </div>
224→              {modelsLoading ? (
225→                <div className="flex items-center gap-2 py-4">
226→                  <Loader2 className="size-4 animate-spin text-muted-foreground" />
227→                  <span className="text-sm text-muted-foreground">
228→                    Loading models...
229→                  </span>
230→                </div>
231→              ) : providerModels && providerModels.length > 0 ? (
232→                <div className="grid gap-2 max-h-80 overflow-y-auto">
233→                  {providerModels.map((m) => {
234→                    const isSelected = selectedModels.has(m.id);
235→                    const isDefault = defaultModel === m.id;
236→                    return (
237→                      <div
238→                        key={m.id}
239→                        className={cn(
240→                          "flex items-center gap-3 rounded-lg border p-3 text-sm transition-colors",
241→                          isSelected
242→                            ? "border-primary bg-primary/5"
243→                            : "hover:bg-accent/50",
244→                        )}
245→                      >
246→                        <button
247→                          type="button"
248→                          disabled={busy}
249→                          onClick={() => toggleModel(m.id)}
250→                          className={cn(
251→                            "flex size-4 shrink-0 items-center justify-center rounded border transition-colors",
252→                            isSelected
253→                              ? "border-primary bg-primary text-primary-foreground"
254→                              : "border-muted-foreground/40",
255→                          )}
256→                        >
257→                          {isSelected && <Check className="size-3" />}
258→                        </button>
259→                        <button
260→                          type="button"
261→                          disabled={busy}
262→                          onClick={() => toggleModel(m.id)}
263→                          className="flex-1 text-left"
264→                        >
265→                          <span className="font-medium">{m.name || m.id}</span>
266→                          <span className="ml-2 text-xs text-muted-foreground font-mono">
267→                            {m.id}
268→                          </span>
269→                        </button>
270→                        {isSelected && (
271→                          <button
272→                            type="button"
273→                            disabled={busy}
274→                            onClick={() => setDefaultModel(m.id)}
