276→                              "shrink-0 rounded-full px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wide transition-colors",
277→                              isDefault
278→                                ? "bg-primary text-primary-foreground"
279→                                : "bg-muted text-muted-foreground hover:bg-muted/80",
280→                            )}
281→                          >
282→                            {isDefault ? "Default" : "Set default"}
283→                          </button>
284→                        )}
285→                      </div>
286→                    );
287→                  })}
288→                </div>
289→              ) : (
290→                <p className="text-sm text-muted-foreground py-2">
291→                  No models found for this provider.
292→                </p>
293→              )}
294→              {selectedModels.size > 0 && (
