322→                ) : (
323→                  "Configure Model"
324→                )}
325→              </Button>
326→            )}
327→        </div>
328→
329→        {/* Configured models list */}
330→        <div className="rounded-lg border bg-card p-4 space-y-3">
331→          <div>
