347→                  key={model.key}
348→                  className="flex items-center justify-between gap-3 rounded-md border bg-background px-3 py-2"
349→                >
350→                  <div>
351→                    <div className="flex flex-wrap items-center gap-2">
352→                      <span className="text-sm font-medium">
353→                        {model.name || model.key}
354→                      </span>
355→                    </div>
356→                    <p className="mt-1 text-xs font-mono text-muted-foreground break-all">
357→                      {model.key}
358→                    </p>
359→                  </div>
