373→                  )}
374→                </li>
375→              ))}
376→            </ul>
377→          ) : (
378→            <p className="text-sm text-muted-foreground">
379→              No models are configured yet. Configure a provider and model above
380→              to get started.
381→            </p>
382→          )}
383→        </div>
384→
385→        {/* Current status (dev only) */}
386→        {process.env.NODE_ENV === "development" && (
387→          <>
388→            {statusLoading ? (
389→              <div className="rounded-lg border p-4">
390→                <p className="text-sm text-muted-foreground">
391→                  Loading current model status...
392→                </p>
393→              </div>
